// GastroBridge: Database types
// This file will be auto-generated by `npx supabase gen types typescript`
// For now, we define the types manually to match our schema

export type UserRole = "restaurant" | "supplier" | "admin";
export type CuisineType =
  | "italiana"
  | "pizzeria"
  | "pesce"
  | "carne"
  | "giapponese"
  | "fusion"
  | "bistrot"
  | "trattoria"
  | "gourmet"
  | "altro";
export type UnitType =
  | "kg"
  | "g"
  | "lt"
  | "ml"
  | "pz"
  | "cartone"
  | "bottiglia"
  | "latta"
  | "confezione"
  // Phase 1 English additions (extend existing enum, non-breaking)
  | "piece"
  | "l"
  | "box"
  | "pallet"
  | "bundle"
  | "other";
export type OrderStatus =
  | "draft"
  | "submitted"
  | "confirmed"
  | "preparing"
  | "shipping"
  | "delivered"
  | "cancelled";
export type PlanType =
  | "free"
  | "pro"
  | "business"
  | "base"
  | "growth"
  | "enterprise";
export type QualityTier = "economy" | "standard" | "premium" | "luxury";
export type CategoryMacro =
  | "carne"
  | "pesce"
  | "verdura"
  | "frutta"
  | "latticini"
  | "secco"
  | "bevande"
  | "surgelati"
  | "panetteria"
  | "altro";
export type CertificationType =
  | "DOP"
  | "IGP"
  | "STG"
  | "BIO"
  | "DOC"
  | "DOCG"
  | "IGT"
  | "HALAL"
  | "KOSHER"
  | "MSC"
  | "ASC"
  | "FAIRTRADE";
export type PresetProfile =
  | "custom"
  | "stellato"
  | "trattoria"
  | "pizzeria"
  | "bar"
  | "mensa";

