// Phase 1 — Supplier Fondamenta: new enums
// ------------------------------------------------------------------
export type SupplierRole = "admin" | "sales" | "warehouse" | "driver";

export type SupplierPermission =
  | "order.read"
  | "order.accept_line"
  | "order.prepare"
  | "pricing.read"
  | "pricing.edit"
  | "catalog.read"
  | "catalog.edit"
  | "stock.read"
  | "stock.receive"
  | "stock.adjust"
  | "ddt.generate"
  | "ddt.manage_templates"
  | "delivery.plan"
  | "delivery.execute"
  | "staff.manage"
  | "settings.manage"
  | "analytics.financial"
  | "reviews.reply";

export type StockMovementType =
  | "receive"
  | "order_reserve"
  | "order_unreserve"
  | "order_ship"
  | "adjust_in"
  | "adjust_out"
  | "return"
  | "transfer";

export type OrderLineStatus =
  | "pending"
  | "accepted"
  | "modified"
  | "rejected";

export type OrderSplitEventType =
  | "received"
  | "accepted"
  | "partially_accepted"
  | "rejected"
  | "stock_conflict"
  | "preparing"
  | "packed"
  | "shipped"
  | "delivered"
  | "canceled";

export type DeliveryStatus =
  | "planned"
  | "loaded"
  | "in_transit"
  | "delivered"
  | "failed";

export type DdtCausale =
  | "sale"
  | "consignment"
  | "return"
  | "transfer"
  | "sample"
  | "cancel";

export type PromotionType = "percentage" | "fixed_amount" | "bundle";

export type NotificationChannel = "email" | "push" | "sms";

export type NotificationEvent =
  | "order_received"
  | "order_accepted"
  | "order_shipped"
  | "order_delivered"
  | "stock_low"
  | "lot_expiring"
  | "delivery_failed"
  | "reorder_suggested";

export type PromotionAppliesTo =
  | "all_catalog"
  | "categories"
  | "products"
  | "customers_segment";

